package main

import (
    "sync"
)

type Bank struct {
    balances map[string]float64
    mutex    sync.RWMutex
}

func NewBank() *Bank {
    return &Bank{
        balances: make(map[string]float64),
        mutex:    sync.RWMutex{},
    }
}

func (b *Bank) GetBalance(account string) float64 {
    b.mutex.RLock()
    defer b.mutex.RUnlock()
    return b.balances[account]
}

func (b *Bank) Deposit(account string, amount float64) error {
    b.mutex.Lock()
    defer b.mutex.Unlock()
    b.balances[account] += amount
    return nil
}

func (b *Bank) Withdraw(account string, amount float64) error {
    b.mutex.Lock()
    defer b.mutex.Unlock()
    if b.balances[account] < amount {
        return fmt.Errorf("insufficient funds")
    }
    b.balances[account] -= amount
    return nil
}

func (b *Bank) Transfer(from, to string, amount float64) error {
    b.mutex.Lock()
    defer b.mutex.Unlock()
    
    if b.balances[from] < amount {
        return fmt.Errorf("insufficient funds")
    }
    
    b.balances[from] -= amount
    b.balances[to] += amount
    return nil
}

func (b *Bank) ProcessTransaction(account string, operation func(float64) float64) float64 {
    b.mutex.Lock()
    defer b.mutex.Unlock()
    b.balances[account] = operation(b.balances[account])
    return b.balances[account]
}